sql:
SELECT m.device_name AS DeviceName, m.next_maintenance_date AS NextMaintenanceDate
FROM medical_devices m
WHERE m.next_maintenance_date = (SELECT MIN(next_maintenance_date) FROM medical_devices);

external_knowledge:
- Recently joined patients: Patients registered in the system within the last three months;
- Haven't started any treatment: No entries in the medical history table indicating any treatment;
- Undergone any tests: No entries in the test results table indicating any tests were done.

sql:
SELECT p.name, p.gender, mh.diagnosis, mh.treatment
FROM patients p
JOIN medical_history mh ON p.patient_id = mh.patient_id;
